argmax.metal_source:
// argmax: per-row argmax along last dim. One threadgroup per row.
#include <metal_stdlib>
using namespace metal;

static inline void simd_argmax(thread float& v, thread uint& i) {
    for (uint s = 16; s > 0; s >>= 1) {
        float ov = simd_shuffle_down(v, s);
        uint  oi = simd_shuffle_down(i, s);
        if (ov > v) { v = ov; i = oi; }
    }
}

kernel void argmax_f32(
    device const float*  x       [[buffer(0)]],
    device       float*  out     [[buffer(1)]],
    constant     uint&   C       [[buffer(2)]],
    uint3 tid3                  [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint tid = tid3.x;
    const uint row = tgid.y;
    device const float* row_ptr = x + row * C;
    const uint sg = tid >> 5;
    const uint lane = tid & 31;

    float best_v = row_ptr[tid];
    uint  best_i = tid;

    simd_argmax(best_v, best_i);

    threadgroup float tg_v[32];
    threadgroup uint  tg_i[32];
    if (lane == 0) { tg_v[sg] = best_v; tg_i[sg] = best_i; }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (sg == 0) {
        best_v = tg_v[lane];
        best_i = tg_i[lane];
        simd_argmax(best_v, best_i);
        if (lane == 0) out[row] = float(best_i);
    }
}

attention_scores.metal_source:
// attention_scores: softmax(Q @ K^T / sqrt(D)).
#include <metal_stdlib>
using namespace metal;

kernel void attention_scores_f32(
    device const float*  Q       [[buffer(0)]],
    device const float*  K       [[buffer(1)]],
    device       float*  O       [[buffer(2)]],
    constant     uint&   S       [[buffer(3)]],
    constant     uint&   D       [[buffer(4)]],
    uint3 tid3                  [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint TG = 1024;
    const uint tid = tid3.x;
    const uint qr = tgid.y;
    if (qr >= S) return;

    threadgroup float qrow[64];      // D
    threadgroup float scores[128];   // S
    threadgroup float reduce[32];

    if (tid < D) qrow[tid] = Q[qr * D + tid];
    threadgroup_barrier(mem_flags::mem_threadgroup);

    const float inv = rsqrt(float(D));

    {
        uint j   = tid >> 3;
        uint sub = tid & 7;
        uint d0  = sub * 8;
        device const float* kr = K + j * D;
        float acc = 0.0f;
        acc += qrow[d0+0] * kr[d0+0];
        acc += qrow[d0+1] * kr[d0+1];
        acc += qrow[d0+2] * kr[d0+2];
        acc += qrow[d0+3] * kr[d0+3];
        acc += qrow[d0+4] * kr[d0+4];
        acc += qrow[d0+5] * kr[d0+5];
        acc += qrow[d0+6] * kr[d0+6];
        acc += qrow[d0+7] * kr[d0+7];
        acc += simd_shuffle_xor(acc, 1);
        acc += simd_shuffle_xor(acc, 2);
        acc += simd_shuffle_xor(acc, 4);
        if (sub == 0) scores[j] = acc * inv;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    float v = (tid < S) ? scores[tid] : -INFINITY;
    float mx_v = simd_max(v);
    if ((tid & 31) == 0) reduce[tid >> 5] = mx_v;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        float m = (tid < 4) ? reduce[tid] : -INFINITY;
        m = simd_max(m);
        if (tid == 0) reduce[0] = m;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    float row_max = reduce[0];

    float e = (tid < S) ? fast::exp(scores[tid] - row_max) : 0.0f;
    if (tid < S) scores[tid] = e;
    float sum = simd_sum(e);
    if ((tid & 31) == 0) reduce[tid >> 5] = sum;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        float s = (tid < 4) ? reduce[tid] : 0.0f;
        s = simd_sum(s);
        if (tid == 0) reduce[0] = s;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    float inv_sum = 1.0f / reduce[0];

    if (tid < S) O[qr * S + tid] = scores[tid] * inv_sum;
}

avg_pool1d.metal_source:
// avg_pool1d: NLC. mean over window.
#include <metal_stdlib>
using namespace metal;

kernel void avg_pool1d_f32(
    device const float*  x       [[buffer(0)]],
    device       float*  y       [[buffer(1)]],
    constant     uint&   N       [[buffer(2)]],
    constant     uint&   L       [[buffer(3)]],
    constant     uint&   C       [[buffer(4)]],
    constant     uint&   K       [[buffer(5)]],
    constant     uint&   stride  [[buffer(6)]],
    uint tid [[thread_position_in_grid]])
{
    const uint L2 = (L - K) / stride + 1;
    const uint total = N * L2 * C;
    const float inv = 1.0f / float(K);
    for (uint idx = tid; idx < total; idx += 64 * 1024) {
        uint n = idx / (L2 * C); uint r = idx % (L2 * C);
        uint l2 = r / C; uint c = r % C;
        float s = 0.0f;
        for (uint k = 0; k < K; ++k) s += x[(n * L + l2 * stride + k) * C + c];
        y[(n * L2 + l2) * C + c] = s * inv;
    }
}

avg_pool2d.metal_source:
// avg_pool2d: NHWC. K=2, stride=2. float4 along C dim.
#include <metal_stdlib>
using namespace metal;

kernel void avg_pool2d_f32(
    device const float*  x       [[buffer(0)]],
    device       float*  y       [[buffer(1)]],
    constant     uint&   N       [[buffer(2)]],
    constant     uint&   H       [[buffer(3)]],
    constant     uint&   W       [[buffer(4)]],
    constant     uint&   C       [[buffer(5)]],
    constant     uint&   K       [[buffer(6)]],
    constant     uint&   stride  [[buffer(7)]],
    uint tid [[thread_position_in_grid]])
{
    const uint H2 = (H - K) / stride + 1;
    const uint W2 = (W - K) / stride + 1;
    const uint C4 = C >> 2;
    const uint total4 = N * H2 * W2 * C4;
    const float inv = 1.0f / float(K * K);

    const uint sW_in = C;
    const uint sH_in = W * C;
    const uint sN_in = H * W * C;

    for (uint idx = tid; idx < total4; idx += 64 * 1024) {
        uint q = idx;
        uint c4 = q % C4;      q /= C4;
        uint w2 = q % W2;      q /= W2;
        uint h2 = q % H2;      uint n = q / H2;

        uint base = n * sN_in + (h2 * stride) * sH_in + (w2 * stride) * sW_in + (c4 << 2);

        float4 v00 = *reinterpret_cast<const device float4*>(x + base);
        float4 v01 = *reinterpret_cast<const device float4*>(x + base + sW_in);
        float4 v10 = *reinterpret_cast<const device float4*>(x + base + sH_in);
        float4 v11 = *reinterpret_cast<const device float4*>(x + base + sH_in + sW_in);

        float4 s = (v00 + v01) + (v10 + v11);
        *reinterpret_cast<device float4*>(y + (idx << 2)) = s * inv;
    }
}

avg_pool3d.metal_source:
// avg_pool3d: NDHWC. K=2, stride=2. M4: float4 along C dim (C=32 is multiple of 4).
#include <metal_stdlib>
using namespace metal;

kernel void avg_pool3d_f32(
    device const float*  x       [[buffer(0)]],
    device       float*  y       [[buffer(1)]],
    constant     uint&   N       [[buffer(2)]],
    constant     uint&   D       [[buffer(3)]],
    constant     uint&   H       [[buffer(4)]],
    constant     uint&   W       [[buffer(5)]],
    constant     uint&   C       [[buffer(6)]],
    constant     uint&   K       [[buffer(7)]],
    constant     uint&   stride  [[buffer(8)]],
    uint tid [[thread_position_in_grid]])
{
    const uint D2 = (D - K) / stride + 1;
    const uint H2 = (H - K) / stride + 1;
    const uint W2 = (W - K) / stride + 1;
    const uint C4 = C >> 2;
    const uint total4 = N * D2 * H2 * W2 * C4;
    const float inv = 1.0f / float(K * K * K);

    const uint sW_in = C;
    const uint sH_in = W * C;
    const uint sD_in = H * W * C;
    const uint sN_in = D * H * W * C;

    for (uint idx = tid; idx < total4; idx += 64 * 1024) {
        uint q = idx;
        uint c4 = q % C4;      q /= C4;
        uint w2 = q % W2;      q /= W2;
        uint h2 = q % H2;      q /= H2;
        uint d2 = q % D2;      uint n = q / D2;

        uint base = n * sN_in + (d2 * stride) * sD_in + (h2 * stride) * sH_in + (w2 * stride) * sW_in + (c4 << 2);

        float4 v000 = *reinterpret_cast<const device float4*>(x + base);
        float4 v001 = *reinterpret_cast<const device float4*>(x + base + sW_in);
        float4 v010 = *reinterpret_cast<const device float4*>(x + base + sH_in);
        float4 v011 = *reinterpret_cast<const device float4*>(x + base + sH_in + sW_in);
        float4 v100 = *reinterpret_cast<const device float4*>(x + base + sD_in);
        float4 v101 = *reinterpret_cast<const device float4*>(x + base + sD_in + sW_in);
        float4 v110 = *reinterpret_cast<const device float4*>(x + base + sD_in + sH_in);
        float4 v111 = *reinterpret_cast<const device float4*>(x + base + sD_in + sH_in + sW_in);

        float4 s = (v000 + v001) + (v010 + v011) + (v100 + v101) + (v110 + v111);
        *reinterpret_cast<device float4*>(y + (idx << 2)) = s * inv;
    }
}

batch_norm.metal_source:
// batchnorm: normalize each column over rows. (1024, 256) input.
#include <metal_stdlib>
using namespace metal;

kernel void batch_norm_f32(
    device const float*  x       [[buffer(0)]],
    device       float*  y       [[buffer(1)]],
    constant     uint&   N       [[buffer(2)]],
    constant     uint&   C       [[buffer(3)]],
    constant     float&  eps     [[buffer(4)]],
    uint3 tid                   [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint t = tid.x;
    const uint col = tgid.y;

    float val = x[t * C + col];
    float s2  = val * val;

    float sum   = simd_sum(val);
    float sumsq = simd_sum(s2);

    threadgroup float tg_sum[32];
    threadgroup float tg_sumsq[32];
    const uint sg = t >> 5;
    if ((t & 31) == 0) {
        tg_sum[sg]   = sum;
        tg_sumsq[sg] = sumsq;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (t < 32) {
        sum   = tg_sum[t];
        sumsq = tg_sumsq[t];
        for (uint s = 16; s > 0; s >>= 1) {
            sum   += simd_shuffle_down(sum,   s);
            sumsq += simd_shuffle_down(sumsq, s);
        }
    }
    if (t == 0) {
        tg_sum[0]   = sum;
        tg_sumsq[0] = sumsq;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    float mean = tg_sum[0] / float(N);
    float var  = max(tg_sumsq[0] / float(N) - mean * mean, 0.0f);
    float inv_std = rsqrt(var + eps);

    y[t * C + col] = (val - mean) * inv_std;
}

bias_add.metal_source:
// bias_add: y[r, c] = x[r, c] + b[c]. float4 grid-stride loop with cached bias.
#include <metal_stdlib>
using namespace metal;

kernel void bias_add_f32(
    device const float*  X        [[buffer(0)]],
    device const float*  B        [[buffer(1)]],
    device       float*  Y        [[buffer(2)]],
    constant     uint&   N_total  [[buffer(3)]],
    constant     uint&   C        [[buffer(4)]],
    constant     uint&   grid_size [[buffer(5)]],
    uint tid                       [[thread_position_in_grid]],
    uint lid                       [[thread_position_in_threadgroup]],
    uint tg_size                   [[threads_per_threadgroup]])
{
    threadgroup float bias_tg[1024];
    for (uint i = lid; i < C; i += tg_size) bias_tg[i] = B[i];
    threadgroup_barrier(mem_flags::mem_threadgroup);

    const uint n4 = N_total >> 2;
    const uint Cmask = C - 1;
    for (uint i = tid; i < n4; i += grid_size) {
        uint base = i << 2;
        float4 x = *reinterpret_cast<const device float4*>(&X[base]);
        float4 b = *reinterpret_cast<const threadgroup float4*>(&bias_tg[base & Cmask]);
        *reinterpret_cast<device float4*>(&Y[base]) = x + b;
    }
}

bias_gelu.metal_source:
// bias_gelu: y = gelu(x + b). float4 with cached bias in threadgroup memory.
#include <metal_stdlib>
using namespace metal;

constant constexpr float gelu_k = 0.79788456f; // sqrt(2/pi)

static inline float4 gelu_tanh4(float4 v) {
    float4 t = gelu_k * (v + 0.044715f * v * v * v);
    return 0.5f * v * (1.0f + tanh(t));
}

kernel void bias_gelu_f32(
    device const float*  X        [[buffer(0)]],
    device const float*  B        [[buffer(1)]],
    device       float*  Y        [[buffer(2)]],
    constant     uint&   N_total  [[buffer(3)]],
    constant     uint&   C        [[buffer(4)]],
    constant     uint&   grid_size [[buffer(5)]],
    uint tid                       [[thread_position_in_grid]],
    uint lid                       [[thread_position_in_threadgroup]],
    uint tg_size                   [[threads_per_threadgroup]])
{
    threadgroup float bias_tg[1024];
    for (uint i = lid; i < C; i += tg_size) bias_tg[i] = B[i];
    threadgroup_barrier(mem_flags::mem_threadgroup);

    const uint n4 = N_total >> 2;
    const uint Cmask = C - 1;
    for (uint i = tid; i < n4; i += grid_size) {
        uint base = i << 2;
        float4 x = *reinterpret_cast<const device float4*>(&X[base]);
        float4 b = *reinterpret_cast<const threadgroup float4*>(&bias_tg[base & Cmask]);
        float4 z = x + b;
        *reinterpret_cast<device float4*>(&Y[base]) = gelu_tanh4(z);
    }
}

clip.metal_source:
#include <metal_stdlib>
using namespace metal;

kernel void clip_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    constant     uint&   grid_size [[buffer(3)]],
